    /**
     * @method
     * @name polymarket#fetchTicker
     * @description fetches the current mid-price and best bid/ask for a single outcome token
     * @see https://docs.polymarket.com/api-reference/data/get-midpoint-price
     * @see https://docs.polymarket.com/api-reference/market-data/get-order-book
     * @param {string} outcome unified outcome like TRUMP_DANCE_TODAY_997:YES or an outcome token id
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTicker(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object outcomeObj = (this.loadOutcome(outcome)).join();
            Object tokenId = Helpers.GetValue(outcomeObj, "outcomeId");
            Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.clobPublicGetMidpoint(new java.util.HashMap<String, Object>() {{
        put( "token_id", tokenId );
    }}), this.clobPublicGetBook(new java.util.HashMap<String, Object>() {{
        put( "token_id", tokenId );
    }})));
            var midpointResponsebookResponseVariable = (Helpers.promiseAll(promises)).join();
            var midpointResponse = ((java.util.List<Object>) midpointResponsebookResponseVariable).get(0);
            var bookResponse = ((java.util.List<Object>) midpointResponsebookResponseVariable).get(1);
            Object response = new java.util.HashMap<String, Object>() {{
                put( "midpoint", midpointResponse );
                put( "book", bookResponse );
            }};
            //
            //     {
            //         "midpoint": {
            //             "mid": "0.9985"
            //         },
            //         "book": {
            //             "market": "0x2d55f622bc12e23dc1f1bb4db8360c28c92155f9376bf73953c0756ee1387b2f",
            //             "asset_id": "16718041887881762329859205887704087070587186248220606272297433440108449709696",
            //             "timestamp": "1777344471023",
            //             "hash": "11aa0feabec970de83b04a2c0d50a7639e144f43",
            //             "bids": [
            //                 {
            //                     "price": "0.45",
            //                     "size": "100"
            //                 },
            //             ],
            //             "asks": [
            //                 {
            //                     "price": "0.46",
            //                     "size": "150"
            //                 },
            //             ],
            //             "min_order_size": "5",
            //             "tick_size": "0.001",
            //             "neg_risk": false,
            //             "last_trade_price": "0.998"
            //         }
            //     }
            //
            return this.parseTicker(response, outcomeObj);
        });

    }

    /**
     * @method
     * @name polymarket#fetchTickers
     * @description fetches tickers for multiple outcome tokens at once using the batched CLOB book and midpoint endpoints
     * @see https://docs.polymarket.com/api-reference/market-data/get-order-books-request-body
     * @see https://docs.polymarket.com/api-reference/market-data/get-midpoint-prices-request-body
     * @param {string[]} [outcomes] unified outcomes or outcome token ids, fetches all loaded outcomes when omitted
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures](https://docs.ccxt.com/#/?id=ticker-structure) indexed by outcome
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcomes = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object outcomesMap = ((Helpers.isTrue((!Helpers.isEqual(this.outcomes, null))))) ? this.outcomes : new java.util.HashMap<String, Object>() {{}};
            Object targets = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            if (Helpers.isTrue(!Helpers.isEqual(outcomes, null)))
            {
                for (var oi = 0; Helpers.isLessThan(oi, Helpers.getArrayLength(outcomes)); oi++)
                {
                    ((java.util.List<Object>)targets).add(Helpers.GetValue(outcomes, oi));
                }
            } else
            {
                Object allOutcomeKeys = Helpers.objectKeys(outcomesMap);
                for (var ki = 0; Helpers.isLessThan(ki, Helpers.getArrayLength(allOutcomeKeys)); ki++)
                {
                    ((java.util.List<Object>)targets).add(Helpers.GetValue(allOutcomeKeys, ki));
                }
            }
            Object outcomesByTokenId = new java.util.HashMap<String, Object>() {{}};
            Object tokenIds = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(targets)); i++)
            {
                Object outcomeObj = this.outcome(Helpers.GetValue(targets, i));
                Object tokenId = this.safeString(outcomeObj, "outcomeId");
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(tokenId, null))) && !Helpers.isTrue((Helpers.inOp(outcomesByTokenId, tokenId)))))
                {
                    Helpers.addElementToObject(outcomesByTokenId, tokenId, outcomeObj);
                    ((java.util.List<Object>)tokenIds).add(tokenId);
                }
            }
            Object chunkSize = this.safeInteger(this.options, "fetchTickersBatchSize", 200);
            Object result = new java.util.HashMap<String, Object>() {{}};
            Object tokenIdsLength = Helpers.getArrayLength(tokenIds);
            Object startIndex = 0;
            while (Helpers.isLessThan(startIndex, tokenIdsLength))
            {
                Object endIndex = this.sum(startIndex, chunkSize);
                if (Helpers.isTrue(Helpers.isGreaterThan(endIndex, tokenIdsLength)))
                {
                    endIndex = tokenIdsLength;
                }
                Object bookParams = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                for (long i = Helpers.toInt64(startIndex); Helpers.isLessThan(i, endIndex); i++)
                {
    final Object finalI = i;
                                    ((java.util.List<Object>)bookParams).add(new java.util.HashMap<String, Object>() {{
                        put( "token_id", Helpers.GetValue(tokenIds, finalI) );
                    }});
                }
                Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.clobPublicPostBooks(bookParams), this.clobPublicPostMidpoints(bookParams)));
                Object responses = (Helpers.promiseAll(promises)).join();
                Object books = Helpers.GetValue(responses, 0);
                Object midpoints = Helpers.GetValue(responses, 1);
                Object booksLength = Helpers.getArrayLength(books);
                for (var i = 0; Helpers.isLessThan(i, booksLength); i++)
                {
                    Object book = Helpers.GetValue(books, i);
                    Object tokenId = this.safeString(book, "asset_id");
                    if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(tokenId, null))) || !Helpers.isTrue((Helpers.inOp(outcomesByTokenId, tokenId)))))
                    {
                        continue;
                    }
                    Object outcomeObj = Helpers.GetValue(outcomesByTokenId, tokenId);
                    Object mid = this.safeString(midpoints, tokenId);
                    Object tickerInput = new java.util.HashMap<String, Object>() {{
                        put( "midpoint", new java.util.HashMap<String, Object>() {{
                            put( "mid", mid );
                        }} );
                        put( "book", book );
                    }};
                    Object ticker = this.parseTicker(tickerInput, outcomeObj);
                    Object symbolKey = this.safeString(ticker, "outcome", tokenId);
                    Helpers.addElementToObject(result, symbolKey, ticker);
                }
                startIndex = this.sum(startIndex, chunkSize);
            }
            return result;
        });

    }

    /**
     * @ignore
     * @method
     * @name polymarket#parseTicker
     * @description parses a combined midpoint + order book response into a unified ticker object
     * @param {object} ticker a dict with midpoint and book entries
     * @param {object} [market] the outcome object the ticker belongs to
     * @returns {object} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "midpoint": {
        //             "mid": "0.9985"
        //         },
        //         "book": {
        //             "market": "0x2d55f622bc12e23dc1f1bb4db8360c28c92155f9376bf73953c0756ee1387b2f",
        //             "asset_id": "16718041887881762329859205887704087070587186248220606272297433440108449709696",
        //             "timestamp": "1777344471023",
        //             "hash": "11aa0feabec970de83b04a2c0d50a7639e144f43",
        //             "bids": [
        //                 {
        //                     "price": "0.45",
        //                     "size": "100"
        //                 },
        //             ],
        //             "asks": [
        //                 {
        //                     "price": "0.46",
        //                     "size": "150"
        //                 },
        //             ],
        //             "min_order_size": "5",
        //             "tick_size": "0.001",
        //             "neg_risk": false,
        //             "last_trade_price": "0.998"
        //         }
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object midpointData = this.safeDict(ticker, "midpoint", new java.util.HashMap<String, Object>() {{}});
        Object bookData = this.safeDict(ticker, "book", new java.util.HashMap<String, Object>() {{}});
        Object mid = this.safeNumber(midpointData, "mid");
        Object bids = (java.util.List<Object>)(this.safeList(bookData, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
        Object asks = (java.util.List<Object>)(this.safeList(bookData, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
        Object bidsLength = Helpers.getArrayLength(bids);
        Object asksLength = Helpers.getArrayLength(asks);
        // the CLOB book endpoint returns levels sorted away from the touch (bids ascending, asks descending), so the best level is the last entry
        Object bestBid = ((Helpers.isTrue((Helpers.isGreaterThan(bidsLength, 0))))) ? Helpers.GetValue(bids, Helpers.subtract(bidsLength, 1)) : null;
        Object bestAsk = ((Helpers.isTrue((Helpers.isGreaterThan(asksLength, 0))))) ? Helpers.GetValue(asks, Helpers.subtract(asksLength, 1)) : null;
        Object lastTradePrice = this.safeNumber(bookData, "last_trade_price");
        Object last = ((Helpers.isTrue((!Helpers.isEqual(lastTradePrice, null))))) ? lastTradePrice : mid;
        Object outcome = this.safeOutcomeSymbol(null, market);
        Object timestamp = this.safeInteger(bookData, "timestamp", this.milliseconds());
        Object quoteVolume = null;
        if (Helpers.isTrue(!Helpers.isEqual(market, null)))
        {
            quoteVolume = this.safeNumber2(Helpers.GetValue(market, "info"), "volume24hr", "volume");
        }
        final Object finalMarket = market;
        final Object finalQuoteVolume = quoteVolume;
        return this.safePredictionTicker(new java.util.HashMap<String, Object>() {{
            put( "outcome", outcome );
            put( "outcomeId", PolymarketCore.this.safeString(finalMarket, "outcomeId") );
            put( "label", PolymarketCore.this.safeString(finalMarket, "label") );
            put( "market", PolymarketCore.this.safeString(finalMarket, "market") );
            put( "timestamp", timestamp );
            put( "datetime", PolymarketCore.this.iso8601(timestamp) );
            put( "high", null );
            put( "low", null );
            put( "bid", PolymarketCore.this.safeNumber(bestBid, "price") );
            put( "bidVolume", PolymarketCore.this.safeNumber(bestBid, "size") );
            put( "ask", PolymarketCore.this.safeNumber(bestAsk, "price") );
            put( "askVolume", PolymarketCore.this.safeNumber(bestAsk, "size") );
            put( "vwap", null );
            put( "open", null );
            put( "close", mid );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", mid );
            put( "baseVolume", null );
            put( "quoteVolume", finalQuoteVolume );
            put( "info", ticker );
        }}, market);
    }

