    /**
     * @method
     * @name polymarket#fetchTrades
     * @description fetches public trade history for a single outcome token from the data API
     * @see https://docs.polymarket.com/api-reference/core/get-trades-for-a-user-or-markets
     * @param {string} outcome unified outcome or outcome token id
     * @param {int} [since] not used by polymarket fetchTrades
     * @param {int} [limit] the maximum number of trades to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [trade structures](https://docs.ccxt.com/#/?id=public-trades)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            Object outcomeObj = (this.loadOutcome(outcome)).join();
            Object tokenId = ((String)Helpers.GetValue(outcomeObj, "outcomeId"));
            Object outcomeInfo = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
            Object conditionId = this.safeString(outcomeInfo, "conditionId");
            if (Helpers.isTrue(Helpers.isEqual(conditionId, null)))
            {
                throw new BadRequest((String)Helpers.add(Helpers.add(this.id, " fetchTrades() requires outcome.info.conditionId for an outcome "), tokenId)) ;
            }
            // the endpoint requires a market conditionId, then its filtered down to the requested outcome
            final Object finalConditionId = conditionId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", finalConditionId );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = (this.dataPublicGetTrades(this.extend(request, parameters))).join();
            Object rawTrades = ((Helpers.isTrue(Helpers.isArray(response)))) ? response : this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object filteredTrades = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawTrades)); i++)
            {
                Object trade = Helpers.GetValue(rawTrades, i);
                Object tradeAsset = this.safeString(trade, "asset");
                if (Helpers.isTrue(Helpers.isEqual(tradeAsset, tokenId)))
                {
                    ((java.util.List<Object>)filteredTrades).add(trade);
                }
            }
            // the trades are already narrowed to this outcome by asset id above;
            // parseTrade resolves the outcome from each trade's asset id
            return this.parsePredictionTrades(filteredTrades, null, since, limit);
        });

    }

    /**
     * @method
     * @name polymarket#fetchMyTrades
     * @description fetches the authenticated user's trade history from the CLOB, optionally filtered by outcome token
     * @see https://docs.polymarket.com/api-reference/trade/get-trades
     * @param {string} [outcome] unified outcome or outcome token id
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [trade structures](https://docs.ccxt.com/#/?id=trade-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadApiCredentials()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object outcomeObj = null;
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                outcomeObj = (this.loadOutcome(outcome)).join();
                Helpers.addElementToObject(request, "asset_id", Helpers.GetValue(outcomeObj, "outcomeId"));
            }
            Object response = (this.clobPrivateGetDataTrades(this.extend(request, parameters))).join();
            Object rawTrades = ((Helpers.isTrue(Helpers.isArray(response)))) ? response : (java.util.List<Object>)(this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
            return this.parsePredictionTrades(rawTrades, outcomeObj, since, limit);
        });

    }

    /**
     * @method
     * @name polymarket#fetchOrderTrades
     * @description fetches all the trades made from a single order
     * @see https://docs.polymarket.com/api-reference/trade/get-trades
     * @param {string} id the order id
     * @param {string} [outcome] unified outcome or outcome token id to narrow the lookup
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [trade structures](https://docs.ccxt.com/#/?id=trade-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderTrades(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // the /data/trades endpoint has no order filter, so fetch the user's trades and keep
            // the ones where this order was the taker or one of the matched makers
            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            Object trades = (this.fetchMyTrades(outcome, null, null, parameters)).join();
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(trades)); i++)
            {
                Object trade = Helpers.GetValue(trades, i);
                Object info = this.safeDict(trade, "info", new java.util.HashMap<String, Object>() {{}});
                Object belongs = Helpers.isTrue((Helpers.isEqual(this.safeString(trade, "order"), id))) || Helpers.isTrue((Helpers.isEqual(this.safeString(info, "taker_order_id"), id)));
                Object makerOrders = this.safeList(info, "maker_orders", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(makerOrders)); j++)
                {
                    if (Helpers.isTrue(Helpers.isEqual(this.safeString(Helpers.GetValue(makerOrders, j), "order_id"), id)))
                    {
                        belongs = true;
                    }
                }
                if (Helpers.isTrue(belongs))
                {
                    ((java.util.List<Object>)result).add(trade);
                }
            }
            return this.filterBySinceLimit(result, since, limit);
        });

    }

    /**
     * @ignore
     * @method
     * @name polymarket#parseTrade
     * @description parses a raw data API trade object into a unified trade object
     * @param {object} trade the raw trade object
     * @param {object} [market] the outcome object the trade belongs to
     * @returns {object} a [trade structure](https://docs.ccxt.com/#/?id=public-trades)
     */
    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        // public data-api trades use 'asset'/'orderId'/'transactionHash'/'timestamp';
        // the private CLOB /data/trades use 'asset_id'/'taker_order_id'/'transaction_hash'/'match_time'
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("transactionHash", "transaction_hash", "id")));
        Object timestamp = this.safeIntegerProduct(trade, "timestamp", 1000);
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            timestamp = this.safeIntegerProduct(trade, "match_time", 1000);
        }
        Object price = this.safeNumber(trade, "price");
        Object amount = this.safeNumber(trade, "size");
        Object rawSide = this.safeStringLower(trade, "side");
        Object side = ((Helpers.isTrue((Helpers.isTrue(Helpers.isEqual(rawSide, "buy")) || Helpers.isTrue(Helpers.isEqual(rawSide, "sell")))))) ? rawSide : null;
        Object assetId = this.safeString2(trade, "asset", "asset_id");
        Object mkt = ((Helpers.isTrue((!Helpers.isEqual(market, null))))) ? market : this.safeOutcome(assetId);
        Object outcome = this.safeOutcomeSymbol(null, mkt);
        Object rawTakerOrMaker = this.safeStringLower(trade, "trader_side");
        Object takerOrMaker = ((Helpers.isTrue((Helpers.isTrue(Helpers.isEqual(rawTakerOrMaker, "taker")) || Helpers.isTrue(Helpers.isEqual(rawTakerOrMaker, "maker")))))) ? rawTakerOrMaker : null;
        Object feeRateBps = this.safeString(trade, "fee_rate_bps");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeRateBps, null)))
        {
            final Object finalFeeRateBps = feeRateBps;
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", "USDC" );
                put( "rate", PolymarketCore.this.parseNumber(Precise.stringDiv(finalFeeRateBps, "10000")) );
            }};
        }
        final Object finalTimestamp = timestamp;
        final Object finalFee = fee;
        return this.safePredictionTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "timestamp", finalTimestamp );
            put( "datetime", PolymarketCore.this.iso8601(finalTimestamp) );
            put( "outcome", outcome );
            put( "outcomeId", assetId );
            put( "label", PolymarketCore.this.safeString(mkt, "label") );
            put( "market", PolymarketCore.this.safeString(mkt, "market") );
            put( "order", PolymarketCore.this.safeString2(trade, "orderId", "taker_order_id") );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", takerOrMaker );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", finalFee );
        }}, mkt);
    }

    /**
     * @method
     * @name polymarket#fetchBalance
     * @description fetches the USDC collateral balance available for trading on the CLOB
     * @see https://docs.polymarket.com/api-reference/trade/get-balance-allowance
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.signatureType] 0=EOA, 1=POLY_PROXY, 2=GNOSIS_SAFE, 3=POLY_1271 (deposit wallet); defaults to options.signatureType
     * @returns {object} a [balance structure](https://docs.ccxt.com/#/?id=balance-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadApiCredentials()).join();
            // the collateral balance is tied to the signature type / funder that holds the USDC
            Object signatureType = this.safeInteger2(parameters, "signatureType", "signature_type", this.safeInteger(this.options, "signatureType", 3));
            Object rest = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("signatureType", "signature_type")));
            Object request = new java.util.HashMap<String, Object>() {{
                put( "asset_type", "COLLATERAL" );
                put( "signature_type", signatureType );
            }};
            Object response = (this.clobPrivateGetBalanceAllowance(this.extend(request, rest))).join();
            return this.parseBalance(response);
        });

    }

    /**
     * @ignore
     * @method
     * @name polymarket#parseBalance
     * @description parses a balance-allowance response into a balances object with a USDC entry
     * @param {object} response the raw balance-allowance response
     * @returns {object} a [balance structure](https://docs.ccxt.com/#/?id=balance-structure)
     */
    public Object parseBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        // 'balance' is the raw USDC collateral in 6-decimal units (e.g. "8992211" = 8.992211 USDC)
        Object raw = this.safeString(response, "balance");
        Object total = null;
        if (Helpers.isTrue(!Helpers.isEqual(raw, null)))
        {
            total = this.parseNumber(Precise.stringDiv(raw, "1000000"));
        }
        final Object finalTotal = total;
        Helpers.addElementToObject(result, "USDC", new java.util.HashMap<String, Object>() {{
    put( "free", finalTotal );
    put( "used", null );
    put( "total", finalTotal );
}});
        return this.safeBalance(result);
    }

    /**
     * @method
     * @name polymarket#fetchPositions
     * @description fetches open outcome token positions for the wallet from the data API
     * @see https://docs.polymarket.com/api-reference/core/get-current-positions-for-a-user
     * @param {string[]} [outcomes] unified outcomes to filter by
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [position structures](https://docs.ccxt.com/#/?id=position-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcomes = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object outcomesLength = 0;
            if (Helpers.isTrue(!Helpers.isEqual(outcomes, null)))
            {
                outcomesLength = Helpers.getArrayLength(outcomes);
            }
            (this.loadOutcomes()).join();
            if (Helpers.isTrue(Helpers.isEqual(this.walletAddress, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " walletAddress is required to fetchPositions")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "user", PolymarketCore.this.walletAddress );
            }};
            Object response = (this.dataPublicGetPositions(this.extend(request, parameters))).join();
            Object positions = (java.util.List<Object>)(this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
            // parse without the base outcome filter (it resolves standard markets, not outcome tokens),
            // then filter by the requested outcomes' token ids ourselves
            Object parsed = this.parsePredictionPositions(positions);
            if (Helpers.isTrue(Helpers.isEqual(outcomesLength, 0)))
            {
                return parsed;
            }
            Object wantedIds = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(outcomes)); i++)
            {
                Object outcomeObj = this.outcome(Helpers.GetValue(outcomes, i));
                Helpers.addElementToObject(wantedIds, Helpers.GetValue(outcomeObj, "outcomeId"), true);
            }
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(parsed)); i++)
            {
                Object position = Helpers.GetValue(parsed, i);
                Object info = this.safeDict(position, "info", new java.util.HashMap<String, Object>() {{}});
                Object assetId = this.safeString(info, "asset");
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(assetId, null))) && Helpers.isTrue((Helpers.inOp(wantedIds, assetId)))))
                {
                    ((java.util.List<Object>)result).add(position);
                }
            }
            return result;
        });

    }

