    /**
     * @ignore
     * @method
     * @name polymarket#parsePosition
     * @description parses a raw data API position object into a unified position object
     * @param {object} position the raw position object
     * @param {object} [market] the outcome object the position belongs to
     * @returns {object} a [position structure](https://docs.ccxt.com/#/?id=position-structure)
     */
    public Object parsePosition(Object position, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object tokenId = this.safeString(position, "asset");
        Object marketData = this.safeOutcome(tokenId, ((Object)market));
        Object size = this.safeNumber(position, "size");
        Object entryPrice = this.safeNumber(position, "avgPrice");
        Object curPrice = this.safeNumber(position, "currentPrice");
        Object notional = null;
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(size, null))) && Helpers.isTrue((!Helpers.isEqual(curPrice, null)))))
        {
            notional = Helpers.multiply(size, curPrice);
        }
        final Object finalSize = size;
        final Object finalNotional = notional;
        final Object finalCurPrice = curPrice;
        return this.safePredictionPosition(new java.util.HashMap<String, Object>() {{
            put( "id", PolymarketCore.this.safeString(position, "id") );
            put( "outcome", PolymarketCore.this.safeString(marketData, "outcome") );
            put( "outcomeId", PolymarketCore.this.safeString(marketData, "outcomeId") );
            put( "market", PolymarketCore.this.safeString(marketData, "market") );
            put( "label", PolymarketCore.this.safeString(marketData, "label") );
            put( "event", PolymarketCore.this.safeString(marketData, "event") );
            put( "timestamp", null );
            put( "datetime", null );
            put( "contracts", finalSize );
            put( "contractSize", 1 );
            put( "side", "long" );
            put( "notional", finalNotional );
            put( "leverage", 1 );
            put( "unrealizedPnl", null );
            put( "realizedPnl", PolymarketCore.this.safeNumber(position, "realizedPnl") );
            put( "collateral", null );
            put( "entryPrice", entryPrice );
            put( "markPrice", finalCurPrice );
            put( "liquidationPrice", null );
            put( "hedged", false );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "marginRatio", null );
            put( "marginMode", "cross" );
            put( "marginType", "cross" );
            put( "percentage", null );
            put( "info", position );
        }});
    }

